INSERT INTO "Course" ("id", "name", "description", "level") VALUES ('4a96dd0c-cc60-4238-b255-5f8015ffb149', 'HSK 1', 'Beginner Chinese. 150 essential words, 9 lessons across China with Lily.', 'hsk1') ON CONFLICT DO NOTHING;
INSERT INTO "Course" ("id", "name", "description", "level") VALUES ('f26f74ef-0e28-4f73-bdc4-740cd064821a', 'HSK 2', 'Elementary Chinese. Coming soon — 300 words, expanded grammar.', 'hsk2') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('4177f051-f9b1-45c1-a8c3-4b7c031e658d', 'Yunnan', '昆明 (Kūnmíng)', 'Yunnan means "South of the Clouds." With 25 of China''s 56 ethnic minority groups, this is China''s most culturally diverse province. The weather is spring-like year-round in Kunming. Ancient tea horse trails wind through mountains, and the Stone Forest looks like a petrified ocean. Locals say Yunnan has four seasons in one mountain — you can experience tropical, temperate, and alpine climates in a single day.', 'Stone Forest (石林 Shílín)', 'The Stone Forest is a UNESCO site of limestone pillars formed over 270 million years. Local legend says it was created by immortals who turned a mountain into a labyrinth to help a young couple escape.', 'Crossing-the-Bridge Noodles (过桥米线 guòqiáo mǐxiàn)', 'A bowl of boiling broth served with raw meats, vegetables, and rice noodles on the side. You "cross the bridge" by adding ingredients yourself — they cook instantly in the hot broth. Legend says a wife invented this to keep noodles hot while crossing a bridge to bring lunch to her scholar husband.', 'Some ethnic minority groups practice "courtship through song" — young people sing to potential partners across valleys. If you can''t sing well, you might stay single!', '{"x":400,"y":460}', 5, '#7c3aed', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/yunnan.jpg', '[{"type":"intro","title":"South of the Clouds","narrative":"Lily flies to Kunming — the ''City of Eternal Spring.'' The air is fresh, the sky impossibly blue. Her grandma''s journal says: ''Yunnan is where China keeps its secrets.''","speaker":"narrator","mood":"peaceful","dialogue":"Lily: ''Kunming has perfect weather. Not hot, not cold. I could stay here forever.''"},{"type":"learn","title":"Weather & Nature","narrative":"Lily hikes the Stone Forest. The limestone pillars rise like petrified trees. She needs nature words.","speaker":"lily","mood":"exploring","dialogue":"Lily: ''The weather is perfect for hiking. But I need words to describe it!''","words":[{"character":"天气","pinyin":"tiān qì","english":"Weather","context":"The weather is great. 天气很好。"},{"character":"冷","pinyin":"lěng","english":"Cold","context":"It is not cold in Kunming."},{"character":"热","pinyin":"rè","english":"Hot","context":"Summer in Yunnan is not too hot."},{"character":"好","pinyin":"hǎo","english":"Good","context":"The weather is good!"}]},{"type":"quiz","title":"Mountain Directions","narrative":"Lily gets a bit lost on the trail. She needs to ask for directions.","dialogue":"Hiker: 你要去哪里？(Where are you going?)","question":"How does Lily ask \"Where is the exit?\"","options":["出口在哪儿？","你好吗？","多少钱？","现在几点？"],"answer":"出口在哪儿？","feedback":"The hiker points. ''那边!'' (Over there!) Lily follows and finds the main trail. Sometimes getting lost leads to the best views."},{"type":"learn","title":"At a Homestay","narrative":"Lily stays with a Bai minority family in Dali. They welcome her with tea and smiles.","speaker":"lily","mood":"grateful","dialogue":"Host: 欢迎！请坐！(Welcome! Please sit!)","words":[{"character":"在","pinyin":"zài","english":"At/in/on","context":"I am in Dali. 我在大理。"},{"character":"家","pinyin":"jiā","english":"Home/family","context":"Their home is warm. 他们的家很温暖。"},{"character":"前面","pinyin":"qián miàn","english":"In front","context":"Erhai Lake is in front. 洱海在前面。"}]},{"type":"quiz","title":"A Gift","narrative":"The Bai grandmother gives Lily a handmade bracelet.","dialogue":"Grandma: 送给你。(A gift for you.)","question":"What should Lily say?","options":["谢谢！很漂亮！","多少钱？","再见！","在哪里？"],"answer":"谢谢！很漂亮！","feedback":"Lily''s eyes fill with tears. ''谢谢,'' she whispers. The grandmother pats her hand. No more words needed."},{"type":"end","title":"Grandma''s Secret","narrative":"Lily writes by Erhai Lake.","speaker":"lily","mood":"reflective","dialogue":"Grandma wrote about this lake. She said it was the most beautiful place in China. She was right. A Bai grandmother gave me a bracelet today. She reminded me of you, Grandma. I''m learning that kindness doesn''t need perfect grammar."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('454e1d2c-349a-47e0-9569-f3ad7db48faf', 'Shaanxi', '西安 (Xī''ān)', 'Welcome to Xi''an, the ancient capital of 13 dynasties and the eastern starting point of the Silk Road. This is where Chinese civilization took root — the Terracotta Army guards the tomb of China''s first emperor, and the city walls (the most complete in China) still encircle the old quarter. The Muslim Quarter buzzes with the smell of cumin-spiced lamb and freshly pulled noodles.', 'Terracotta Warriors (兵马俑 Bīngmǎyǒng)', 'Over 8,000 life-sized soldiers, each with unique facial features, were buried to protect Emperor Qin Shi Huang in the afterlife. They were discovered in 1974 by farmers digging a well — and excavation is still ongoing.', 'Biangbiang Noodles (油泼面 yóupōmiàn)', 'Wide, hand-pulled belt noodles drenched in sizzling chili oil, garlic, and vinegar. The character "biáng" is one of the most complex in Chinese with 58 strokes!', 'Xi''an locals love to ask "你吃了吗?" (Have you eaten?) as a greeting. The correct answer is "吃了" even if you haven''t — it''s not an invitation, just a warm hello.', '{"x":570,"y":280}', 2, '#ea580c', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/shaanxi.jpg', '[{"type":"intro","title":"The Ancient Capital","narrative":"Lily arrives in Xi''an by high-speed train. The city walls loom ahead — the most complete ancient city walls in China. She checks her grandma''s journal: ''Xi''an — where 13 dynasties began. Walk the walls and feel history under your feet.''","speaker":"narrator","mood":"excited","dialogue":"Lily: ''Grandma walked these same walls 40 years ago. I''m literally following in her footsteps.''"},{"type":"learn","title":"Time Words","narrative":"Lily checks her watch. The Terracotta Warriors museum opens at 9am. She needs to ask about times and dates.","speaker":"lily","mood":"focused","dialogue":"Lily: ''I need to know: what time does it open? When should I go?''","words":[{"character":"今天","pinyin":"jīn tiān","english":"Today","context":"Today Lily visits the warriors."},{"character":"明天","pinyin":"míng tiān","english":"Tomorrow","context":"Tomorrow she explores the Muslim Quarter."},{"character":"点","pinyin":"diǎn","english":"O''clock","context":"The museum opens at 9 o''clock."},{"character":"几","pinyin":"jǐ","english":"How many (≤10)","context":"What time? 几点?"}]},{"type":"quiz","title":"Museum Hours","narrative":"Lily asks a guard at the museum entrance.","dialogue":"Lily: 请问，几点开门？(Excuse me, what time does it open?)","question":"What is Lily asking?","options":["Where is the museum?","What time does it open?","How much is the ticket?","Can I take photos?"],"answer":"What time does it open?","feedback":"The guard smiles. ''九点!'' (9 o''clock!) Lily checks her watch — 8:45. Perfect timing!"},{"type":"learn","title":"Asking Questions","narrative":"Inside the museum, Lily is overwhelmed by thousands of warriors. She has so many questions.","speaker":"lily","mood":"curious","dialogue":"Lily: ''Who made these? How many are there? I need question words!''","words":[{"character":"什么","pinyin":"shén me","english":"What","context":"What is this? 这是什么？"},{"character":"谁","pinyin":"shuí","english":"Who","context":"Who made these? 谁做的？"},{"character":"多少","pinyin":"duō shao","english":"How many/much","context":"How many warriors? 多少兵马俑？"}]},{"type":"quiz","title":"A Curious Traveler","narrative":"Lily wants to ask the guide how many warriors were buried.","dialogue":"Guide: 这里有八千多个兵马俑。(There are over 8,000 warriors here.)","question":"What question did Lily probably ask?","options":["谁做的？(Who made them?)","多少钱？(How much?)","多少个？(How many?)","几点？(What time?)"],"answer":"多少个？(How many?)","feedback":"''八千多个!'' the guide says. Lily''s jaw drops. Eight THOUSAND life-sized warriors, each with a unique face."},{"type":"end","title":"Following Footsteps","narrative":"That evening, Lily walks the city walls at sunset. The ancient stones glow orange. She writes in her journal:","speaker":"lily","mood":"reflective","dialogue":"Day 3. I walked where emperors walked. I learned to ask questions — 什么, 谁, 多少. A guide told me each warrior has a different face. Like each person I meet here. Grandma, I''m starting to hear your voice in this language."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('d7d98dea-244a-4065-9306-84e8eaa5398b', 'Shanghai', '上海 (Shànghǎi)', 'Shanghai is China''s dazzling future. The Bund''s colonial-era buildings face Pudong''s neon skyline across the Huangpu River — two centuries staring at each other. Once a fishing village, Shanghai exploded into Asia''s most cosmopolitan city in the 1920s, earning the nickname "Paris of the East." Today, it''s where China''s best chefs, artists, and entrepreneurs come to make their mark.', 'The Bund (外滩 Wàitān)', 'The Bund has 52 buildings of various architectural styles — Gothic, Baroque, Romanesque, and Art Deco — built by British, French, American, and Russian traders during the concession era.', 'Xiaolongbao (小笼包 xiǎolóngbāo)', 'Delicate soup dumplings with paper-thin skin, filled with pork and a burst of hot broth. The proper way to eat: nibble a small hole, slurp the soup, then eat the dumpling. Biting directly = burnt tongue.', 'Shanghainese are famous for their business savvy and style. "Shanghai speed" (上海速度) refers to how fast things move here — construction, deals, fashion trends.', '{"x":700,"y":370}', 4, '#2563eb', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/shanghai.jpg', '[{"type":"intro","title":"City of the Future","narrative":"Lily steps out of Shanghai Hongqiao Station into a canyon of glass skyscrapers. After ancient Xi''an and laid-back Chengdu, Shanghai feels like the future.","speaker":"narrator","mood":"excited","dialogue":"Lily: ''Everything here sparkles. I feel like I need to upgrade my entire wardrobe just to fit in.''"},{"type":"learn","title":"Shopping","narrative":"Lily hits Nanjing Road — China''s most famous shopping street. She needs shopping vocabulary.","speaker":"lily","mood":"excited","dialogue":"Lily: ''I want to buy something. But I don''t know how to ask the price!''","words":[{"character":"买","pinyin":"mǎi","english":"To buy","context":"I want to buy this. 我想买这个。"},{"character":"钱","pinyin":"qián","english":"Money","context":"How much money? 多少钱？"},{"character":"多少","pinyin":"duō shao","english":"How much","context":"How much is this? 这个多少钱？"},{"character":"商店","pinyin":"shāng diàn","english":"Shop","context":"Nanjing Road has many shops."}]},{"type":"quiz","title":"At the Market","narrative":"Lily finds a beautiful silk scarf. She wants to know the price.","dialogue":"Vendor: 很漂亮，对不对？(Beautiful, right?)","question":"What should Lily ask?","options":["这个多少钱？","这是什么？","你叫什么名字？","现在几点？"],"answer":"这个多少钱？","feedback":"''八十块!'' the vendor says. 80 yuan. Lily''s first shopping interaction in Chinese — and it worked!"},{"type":"learn","title":"The Bund","narrative":"At sunset, Lily walks the Bund. The colonial buildings on one side, neon skyscrapers on the other.","speaker":"narrator","mood":"inspired","dialogue":"Lily: ''This is the most beautiful skyline I''ve ever seen. I need the word for beautiful.''","words":[{"character":"漂亮","pinyin":"piào liang","english":"Beautiful","context":"The Bund is beautiful. 外滩很漂亮。"},{"character":"大","pinyin":"dà","english":"Big","context":"Shanghai is a big city."},{"character":"有","pinyin":"yǒu","english":"To have","context":"Shanghai has many buildings."}]},{"type":"quiz","title":"Soup Dumplings","narrative":"Lily tries xiaolongbao — Shanghai''s famous soup dumplings.","dialogue":"Server: 小心！很烫！(Careful! Very hot!)","question":"Lily wants to say \"This is too delicious!\" What should she say?","options":["太好吃了！(Too delicious!)","太辣了！(Too spicy!)","太冷了！(Too cold!)","太大了！(Too big!)"],"answer":"太好吃了！(Too delicious!)","feedback":"The soup bursts in her mouth — rich, savory, perfect. Lily understands why people line up for hours."},{"type":"end","title":"East Meets West","narrative":"Lily writes on the Bund at night.","speaker":"lily","mood":"reflective","dialogue":"I bought a scarf. I ate soup dumplings. I told a vendor ''很漂亮'' — and meant it. Shanghai feels like two cities in one: old and new, East and West. Grandma''s journal says she came here in 1985, when Pudong was still farmland. Now it touches the clouds."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('6bef1815-3d73-4220-8a44-550ec954e10c', 'Sichuan', '成都 (Chéngdū)', 'Welcome to Chengdu, the land of abundance! Sichuan is famous for two things: pandas and spice. The Sichuan Basin''s muggy climate gave birth to fiery cuisine — locals say the chili heat drives out the dampness. Life here moves slower than in Beijing or Shanghai; the local motto is "巴适" (bāshì) — comfortable, relaxed. Teahouses line every street, and you can spend an entire afternoon sipping jasmine tea while getting your ears cleaned (a local tradition!).', 'Chengdu Panda Base (大熊猫基地 Dàxióngmāo Jīdì)', 'Pandas eat 12-38 kg of bamboo daily and spend 10-16 hours eating. Despite having a carnivore''s digestive system, they evolved to live almost entirely on bamboo.', 'Hotpot (火锅 huǒguō)', 'A bubbling cauldron of chili oil and Sichuan peppercorns that numbs your tongue (málà 麻辣). You cook raw meats, vegetables, and tofu right at your table. The numbing sensation from Sichuan peppercorns is called "má" — a unique feeling you won''t find anywhere else.', 'Sichuan opera features "face-changing" (变脸 biànliǎn) where performers instantly switch colorful masks with a sweep of the hand — the technique is a closely guarded secret.', '{"x":460,"y":360}', 3, '#16a34a', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/sichuan.jpg', '[{"type":"intro","title":"Too Spicy!","narrative":"Lily arrives in Chengdu to the smell of chili oil and Sichuan peppercorns. Her hostel owner immediately offers her hotpot. ''It''s the local specialty!'' Lily is excited — and terrified.","speaker":"narrator","mood":"nervous","dialogue":"Lily: ''I''ve heard Sichuan food is spicy. But how spicy can it really be?''"},{"type":"learn","title":"Food & Eating","narrative":"At the hotpot restaurant, the bubbling red broth looks like lava. Lily needs to order food.","speaker":"lily","mood":"nervous","dialogue":"Waiter: 你想吃什么？(What do you want to eat?)\nLily: ''I need food words. Fast.''","words":[{"character":"吃","pinyin":"chī","english":"To eat","context":"I want to eat hotpot. 我想吃火锅。"},{"character":"喝","pinyin":"hē","english":"To drink","context":"I want to drink tea. 我想喝茶。"},{"character":"水","pinyin":"shuǐ","english":"Water","context":"Lily needs water after spicy food!"},{"character":"米饭","pinyin":"mǐ fàn","english":"Rice","context":"Rice helps with the spice."}]},{"type":"quiz","title":"First Bite","narrative":"Lily takes her first bite. Her mouth is ON FIRE.","dialogue":"Lily: (eyes watering) ''太...太...'' (Too... too...)","question":"What word should Lily use?","options":["太辣了！(Too spicy!)","太冷了！(Too cold!)","太好了！(Great!)","太少了！(Too little!)"],"answer":"太辣了！(Too spicy!)","feedback":"The waiter laughs kindly and hands her a glass of milk. ''Sichuan people eat this every day!'' Lily can''t imagine."},{"type":"learn","title":"Panda Love","narrative":"The next day, Lily volunteers at the Chengdu Panda Base. She''s surrounded by baby pandas.","speaker":"lily","mood":"happy","dialogue":"Lily: ''These pandas are... there''s no word. Wait, yes there is!''","words":[{"character":"可爱","pinyin":"kě ài","english":"Cute","context":"Pandas are too cute! 熊猫太可爱了！"},{"character":"大","pinyin":"dà","english":"Big","context":"Adult pandas are big."},{"character":"小","pinyin":"xiǎo","english":"Small","context":"Baby pandas are small."},{"character":"喜欢","pinyin":"xǐ huān","english":"To like","context":"I like pandas. 我喜欢熊猫。"}]},{"type":"quiz","title":"Tea House Culture","narrative":"After the panda base, Lily visits a traditional tea house. The tea master performs an elegant ceremony.","dialogue":"Tea master: 请喝茶。(Please drink tea.)","question":"How does Lily say \"I like drinking tea\"?","options":["我喜欢喝茶","我喝茶很大","茶太辣了","我喜欢吃茶"],"answer":"我喜欢喝茶","feedback":"The tea master nods approvingly. Lily sits back and enjoys her jasmine tea. This is 巴适 (bāshì) — the Chengdu word for ''everything is just right.''"},{"type":"end","title":"Finding 巴适","narrative":"Lily writes in her journal at the tea house.","speaker":"lily","mood":"reflective","dialogue":"I ate fire today. I learned ''太辣了'' the hard way. But I also learned ''可爱'' — because pandas. And I discovered 巴适 — the feeling when everything is simply, perfectly good. Chengdu, you''ve taught me well."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('0dffd1de-a3fc-4a27-95fb-683abf3a3963', 'Guangdong', '广州 (Guǎngzhōu)', 'Guangzhou (Canton) has been China''s southern gateway for over 2,000 years. When the West first traded with China, it all happened here. Cantonese culture prizes family, food, and entrepreneurship — the famous phrase "吃在广州" means "to eat, go to Guangzhou." Dim sum is not just a meal but a weekend ritual where families gather for hours of tea and small plates.', 'Canton Tower (广州塔 Guǎngzhōu Tǎ)', 'At 600 meters, Canton Tower was the world''s tallest tower when completed in 2010. Its "twisted hourglass" shape is designed to withstand typhoons — it can sway up to 1.5 meters in strong winds.', 'Dim Sum (点心 diǎnxīn)', 'A parade of bite-sized dishes served in bamboo steamers: har gow (shrimp dumplings), siu mai (pork dumplings), char siu bao (BBQ pork buns), egg tarts, and more. Dim sum means "touch the heart" — each dish is meant to be just a taste.', 'Cantonese people tap two fingers on the table when someone pours them tea — a silent "thank you." Legend says an emperor once disguised himself as a commoner and poured tea for his servant, who couldn''t bow (it would blow his cover), so the servant tapped fingers instead — a bow in miniature.', '{"x":580,"y":520}', 6, '#d946ef', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/guangdong.jpg', '[{"type":"intro","title":"Family Ties","narrative":"Lily takes a train to Guangzhou. She''s nervous — she''s meeting her cousin Mei for the first time. Family she never knew she had.","speaker":"narrator","mood":"nervous","dialogue":"Lily: ''I have family here? Cousins I''ve never met? What do I even call them?''"},{"type":"learn","title":"Family Words","narrative":"Mei meets Lily at the station. She''s warm, funny, and speaks a mix of Mandarin and Cantonese.","speaker":"mei","mood":"warm","dialogue":"Mei: 你好！我是你的表妹！(Hello! I''m your cousin!)","words":[{"character":"爸爸","pinyin":"bà ba","english":"Father","context":"Lily''s father is Mei''s uncle."},{"character":"妈妈","pinyin":"mā ma","english":"Mother","context":"Their grandmothers were sisters."},{"character":"朋友","pinyin":"péng yǒu","english":"Friend","context":"Mei quickly becomes Lily''s friend."},{"character":"认识","pinyin":"rèn shi","english":"To know (a person)","context":"Nice to meet you! 认识你很高兴！"}]},{"type":"quiz","title":"Dim Sum Morning","narrative":"Mei takes Lily for dim sum. The table fills with bamboo steamers.","dialogue":"Mei: 你会用筷子吗？(Can you use chopsticks?)","question":"How does Lily say \"I can use chopsticks\"?","options":["我会用筷子","我喜欢筷子","筷子很大","我不会筷子"],"answer":"我会用筷子","feedback":"Mei grins. ''Good! Because forks are NOT an option here!'' She piles more dumplings onto Lily''s plate."},{"type":"learn","title":"Jobs & Life","narrative":"Over tea, Mei asks Lily about her life in America. Lily asks about Mei''s work.","speaker":"mei","mood":"warm","dialogue":"Mei: 你做什么工作？(What do you do for work?)","words":[{"character":"工作","pinyin":"gōng zuò","english":"Work/job","context":"What work do you do? 你做什么工作？"},{"character":"老师","pinyin":"lǎo shī","english":"Teacher","context":"Mei is a teacher. 我是老师。"},{"character":"学生","pinyin":"xué shēng","english":"Student","context":"Lily is a student of Chinese."},{"character":"医生","pinyin":"yī shēng","english":"Doctor","context":"Their aunt is a doctor."}]},{"type":"quiz","title":"The Tea Tap","narrative":"Mei pours tea for Lily. An older relative taps two fingers on the table.","dialogue":"Lily: ''Why did she tap the table?''","question":"What does the finger tapping mean?","options":["She is impatient","Thank you (for pouring tea)","The tea is too hot","She wants more tea"],"answer":"Thank you (for pouring tea)","feedback":"Mei explains the legend of the emperor in disguise. Lily tries it herself when pouring tea for Mei. The gesture feels natural — a silent thank you."},{"type":"end","title":"New Family","narrative":"Lily writes in her journal after the family dinner.","speaker":"lily","mood":"grateful","dialogue":"I have family here. Real family. Mei taught me to tap two fingers to say thank you. We laughed at my Cantonese attempts. Grandma, you never told me about them. But I think you wanted me to find them myself."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('deaf9549-9a72-4827-880f-004120365c2c', 'Beijing', '北京 (Běijīng)', 'Welcome to Beijing, the heart of China! As the capital for over 800 years, Beijing blends imperial grandeur with modern energy. The city is laid out in concentric rings radiating from the Forbidden City — once home to 24 emperors and off-limits to commoners for 500 years. Today, hutongs (narrow alleys) wind through the old city where neighbors still greet each other with "吃了吗?" (Have you eaten?).', 'The Great Wall (长城 Chángchéng)', 'The Great Wall stretches over 21,000 km — long enough to wrap halfway around the Earth. The most famous section, Badaling, is just a 1-hour drive from Beijing. Soldiers used smoke signals by day and fire beacons by night to warn of invasions.', 'Peking Duck (北京烤鸭 Běijīng kǎoyā)', 'Crispy, glossy skin with tender meat, sliced tableside and wrapped in thin pancakes with hoisin sauce, cucumber, and scallions. A dish once reserved for the imperial court.', 'When greeting someone, a slight nod or handshake is common. Address people by title + surname (Teacher Wang, not just Wang). Accept business cards with both hands.', '{"x":650,"y":200}', 1, '#dc2626', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/beijing.jpg', '[{"type":"intro","title":"Touchdown in Beijing","narrative":"Lily Chen steps off the plane at Beijing Daxing Airport. The terminal is enormous — glass, steel, and signs everywhere. Signs she cannot read. She clutches her backpack tighter. Her grandma''s old travel journal is inside. ''Day 1,'' she whispers to herself. ''I''m really here.''","speaker":"narrator","mood":"nervous","dialogue":"Lily: ''I can''t read a single sign. What did I get myself into?''"},{"type":"learn","title":"Your First Words","narrative":"Lily walks through the terminal, overwhelmed. A young woman notices her confused expression and approaches with a warm smile.","speaker":"narrator","mood":"helpful","dialogue":"Stranger: 你好！(Hello!)\nLily freezes. She knows this one! Her grandma used to say it. She takes a breath...","words":[{"character":"你好","pinyin":"nǐ hǎo","english":"Hello","context":"The most important greeting. Say it to anyone, anytime."},{"character":"谢谢","pinyin":"xiè xie","english":"Thank you","context":"Lily wants to thank the stranger for helping her."},{"character":"再见","pinyin":"zài jiàn","english":"Goodbye","context":"How Lily will say goodbye when she leaves the airport."},{"character":"是","pinyin":"shì","english":"To be (is/am/are)","context":"Lily thinks: ''This IS Beijing. I AM here.''"},{"character":"我叫","pinyin":"wǒ jiào","english":"My name is...","context":"How Lily will introduce herself. Point to yourself and say it!"}]},{"type":"quiz","title":"A Friendly Face","narrative":"The stranger smiles and points to herself.","dialogue":"Stranger: 我叫王芳。你叫什么名字？ (I''m Wang Fang. What''s your name?)","question":"Wang Fang just introduced herself and asked Lily''s name. What should Lily say?","options":["再见 (Goodbye)","你好，我叫Lily (Hello, I am Lily)","谢谢 (Thank you)","是 (Yes)"],"answer":"你好，我叫Lily","feedback":"Lily takes a breath. ''你好，我叫Lily!'' she says. Wang Fang beams. ''Lily! 很好听的名字！'' (What a beautiful name!) Lily''s first self-introduction — and it worked! The words feel clumsy in her mouth, but Wang Fang understands perfectly. Lily feels a tiny spark of confidence."},{"type":"scene","title":"The Address","narrative":"Wang Fang walks Lily to the subway station. Lily pulls out a crumpled piece of paper — her grandma''s old hutong address. She shows it to Wang Fang, who nods enthusiastically.","speaker":"narrator","mood":"hopeful","dialogue":"Wang Fang: 哦！胡同！很漂亮！(Oh! Hutong! Very beautiful!)\nLily: (thinking) ''I need to remember the house number... what are the Chinese numbers?''"},{"type":"learn","title":"Numbers 1-10","narrative":"Lily counts on her fingers, remembering the numbers her grandma taught her when she was little. She needs them for the address.","speaker":"lily","mood":"focused","dialogue":"Lily: ''My grandma''s house is number 8. What is 8 in Chinese?''","words":[{"character":"一","pinyin":"yī","english":"One","context":"One suitcase. Lily packed light."},{"character":"二","pinyin":"èr","english":"Two","context":"Two hands to carry her dreams."},{"character":"三","pinyin":"sān","english":"Three","context":"Three flights to get here: SF to Tokyo to Beijing."},{"character":"八","pinyin":"bā","english":"Eight","context":"Grandma''s house number. The luckiest number!"}]},{"type":"quiz","title":"Finding Home","narrative":"Lily stands in front of a traditional courtyard gate. This is it — her grandma''s hutong. An elderly neighbor peers at her curiously.","dialogue":"Neighbor: 你是...？(You are...?)","question":"Lily wants to say: ''Hello, my name is Lily.'' What should she say?","options":["谢谢，再见！","你好，我叫Lily！","八，是八！","我叫王芳。"],"answer":"你好，我叫Lily！","feedback":"The neighbor''s face breaks into a huge grin. ''小莉！你奶奶的孙女！'' (Xiao Li! Your grandmother''s granddaughter!) She remembers Lily''s grandma. Lily feels tears prick her eyes."},{"type":"scene","title":"Tea with a Stranger","narrative":"The neighbor — Auntie Zhang — insists Lily come in for tea. Lily''s tired, hungry, and overwhelmed, but Auntie Zhang''s warmth feels familiar. She motions Lily to sit.","speaker":"narrator","mood":"warm","dialogue":"Auntie Zhang: 请坐！请喝茶！(Please sit! Please drink tea!)\nLily: (thinking) ''I know 请 means please... I think she''s offering me something?''"},{"type":"learn","title":"Being Polite","narrative":"Lily remembers: Chinese culture values politeness deeply. Auntie Zhang is being incredibly generous. Lily wants to be respectful.","speaker":"lily","mood":"grateful","dialogue":"Lily: ''I need to know how to say please, thank you, and sorry. Grandma would want me to be polite.''","words":[{"character":"请","pinyin":"qǐng","english":"Please","context":"Auntie Zhang says ''请坐'' (please sit). It shows care and respect."},{"character":"对不起","pinyin":"duì bu qǐ","english":"Sorry","context":"Lily accidentally knocks over her teacup. She needs this word!"},{"character":"不客气","pinyin":"bú kè qì","english":"You''re welcome","context":"What Auntie Zhang will say when Lily thanks her."},{"character":"好","pinyin":"hǎo","english":"Good","context":"The tea is 很好 (very good). Lily''s first adjective!"}]},{"type":"quiz","title":"An Accident","narrative":"Lily reaches for a photo on the table and accidentally knocks over her teacup. Tea spills across the table. She feels her face burn with embarrassment.","dialogue":"Auntie Zhang: (laughing gently) 没关系，没关系！(It doesn''t matter!)","question":"What should Lily say after spilling the tea?","options":["你好！","对不起！","再见！","谢谢！"],"answer":"对不起！","feedback":"Auntie Zhang pats Lily''s hand. ''没关系！'' she says warmly. Lily learns that mistakes are okay here. No one expects her to be perfect. She''s trying — and that''s what matters."},{"type":"end","title":"Day 1 — Complete","narrative":"That evening, Lily sits on the kang bed in her grandma''s old room. The courtyard is quiet. She opens the travel journal to a fresh page and writes:","speaker":"lily","mood":"reflective","dialogue":"Day 1. I said my first Chinese words today. 你好. 谢谢. 对不起. Eight words total. A stranger helped me. A neighbor remembered Grandma. I spilled tea and survived. Grandma, I think you''d be proud. Tomorrow I explore Beijing. I''ll need more words.\n\nShe closes the journal. Outside, Beijing hums softly. She''s really here."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('2c0319cd-8f99-4f52-8f4f-75699c40b0c6', 'Henan', '郑州 (Zhèngzhōu)', 'Henan is where Chinese civilization was born. The Yellow River gave life to the first dynasties here over 4,000 years ago. Shaolin Temple — the birthplace of Zen Buddhism and kung fu — sits on Song Mountain. Shaolin monks train from childhood, mastering incredible physical feats through discipline and meditation. The Longmen Grottoes hold over 100,000 Buddhist statues carved into limestone cliffs.', 'Shaolin Temple (少林寺 Shàolín Sì)', 'Shaolin kung fu includes over 700 fighting styles. Monks train by carrying water buckets up mountain paths, punching iron plates, and standing in horse stance for hours. The temple was featured in countless martial arts films and inspired the Wu-Tang Clan.', 'Huìmiàn (烩面 Braised Noodles)', 'A rich lamb bone broth with hand-pulled noodles, wood ear mushrooms, and tofu skin. This is the soul food of Henan — warming, nourishing, and deeply satisfying.', 'The "Shaolin greeting" is a right fist pressed against an open left palm (抱拳礼). The fist represents martial power, the open palm represents wisdom — together they symbolize balance between strength and knowledge.', '{"x":610,"y":310}', 7, '#f59e0b', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/henan.jpg', '[{"type":"intro","title":"Shaolin Dreams","narrative":"Lily arrives at Shaolin Temple on Song Mountain. She''s watched kung fu movies her whole life. The real thing is... humbling. Young monks practice in perfect synchronization, their movements impossibly precise.","speaker":"narrator","mood":"inspired","dialogue":"Lily: ''I tried to copy their stance. I lasted about 10 seconds before my legs gave out.''"},{"type":"learn","title":"Abilities","narrative":"A young monk offers to teach Lily basic stances. She needs to talk about abilities.","speaker":"monk","mood":"patient","dialogue":"Monk: 你会做什么？(What can you do?)","words":[{"character":"会","pinyin":"huì","english":"Can (learned skill)","context":"I can speak a little Chinese. 我会说一点中文。"},{"character":"能","pinyin":"néng","english":"Can (ability/possibility)","context":"Can you teach me? 你能教我吗？"},{"character":"写","pinyin":"xiě","english":"To write","context":"I can write some characters."},{"character":"学","pinyin":"xué","english":"To learn","context":"I am learning kung fu. 我在学功夫。"}]},{"type":"quiz","title":"The Monk''s Lesson","narrative":"After trying (and failing) at kung fu, Lily asks the monk a question.","dialogue":"Lily: 功夫很难吗？(Is kung fu hard?)","question":"What does the monk probably answer?","options":["很容易！(Very easy!)","慢慢学。(Learn slowly.)","很便宜。(Very cheap.)","很大。(Very big.)"],"answer":"慢慢学。(Learn slowly.)","feedback":"''Kung fu is not about speed,'' the monk says. ''It''s about patience. Same as learning Chinese. One word at a time.''"},{"type":"learn","title":"Asking for Help","narrative":"Later, Lily gets lost in the temple complex. She needs to ask someone for directions.","speaker":"lily","mood":"lost","dialogue":"Lily: ''I need to ask for help. How do I say it?''","words":[{"character":"请问","pinyin":"qǐng wèn","english":"Excuse me / May I ask","context":"Excuse me, where is the exit?"},{"character":"问","pinyin":"wèn","english":"To ask","context":"I want to ask a question."},{"character":"说","pinyin":"shuō","english":"To speak","context":"Please speak slowly. 请慢慢说。"}]},{"type":"quiz","title":"Finding the Way","narrative":"Lily approaches a senior monk sweeping the courtyard.","dialogue":"Monk: 你要去哪里？(Where do you want to go?)","question":"What should Lily say?","options":["请问，出口在哪儿？","你好吗？","功夫很难。","我喜欢这里。"],"answer":"请问，出口在哪儿？","feedback":"The monk smiles and points with his broom. ''一直走。'' (Go straight.) Lily bows — the Shaolin greeting, fist in palm. The monk bows back."},{"type":"end","title":"Patience","narrative":"Lily writes on the bus leaving Shaolin.","speaker":"lily","mood":"reflective","dialogue":"I can''t do kung fu. But I learned something better: patience. The monk said learning Chinese is like kung fu — you don''t master it in a day. You show up, practice, fall down, get back up. One word at a time. 慢慢来."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('daafe1b8-ccbb-4e89-abb1-a35a8daeeae3', 'Xinjiang', '乌鲁木齐 (Wūlǔmùqí)', 'Xinjiang — the "New Frontier" — is China''s largest province, spanning deserts, mountains, and grasslands where the Silk Road once connected East and West. Uyghur culture blends Central Asian and Chinese influences. The Sunday bazaar in Kashgar has been held for over 2,000 years — you can still buy carpets, spices, and livestock the way Marco Polo described. The Tianshan Mountains ("Celestial Mountains") feed crystal-blue alpine lakes.', 'Kashgar Old City (喀什古城 Kāshí Gǔchéng)', 'Kashgar''s maze-like old city is made of mud-brick houses connected by winding alleys so narrow that cars can''t enter. Historically at the crossroads of the Silk Road, traders from Persia, India, and China all passed through here.', 'Lamb Skewers (羊肉串 yángròu chuàn)', 'Chunks of lamb seasoned with cumin and chili, grilled over charcoal until smoky and crisp on the outside, tender inside. Vendors fan the flames and the smell drifts through entire streets.', 'Uyghur hospitality is legendary — if invited to a home, you''ll be served tea, naan, and dried fruits. Refusing is impolite. The traditional greeting involves placing your right hand over your heart with a slight bow.', '{"x":280,"y":160}', 8, '#0891b2', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/xinjiang.jpg', '[{"type":"intro","title":"The Silk Road","narrative":"Lily flies to Urumqi, then takes a bumpy bus to Kashgar. The landscape transforms — deserts, snow-capped mountains, oasis towns. This was the Silk Road. Traders, pilgrims, travelers — they all passed through here.","speaker":"narrator","mood":"adventurous","dialogue":"Lily: ''The Sunday bazaar has been running for 2,000 years. Marco Polo walked here. Now me.''"},{"type":"learn","title":"Getting Around","narrative":"Lily needs to navigate the sprawling bazaar. Transportation words are essential.","speaker":"lily","mood":"focused","dialogue":"Lily: ''I need to get around. Taxi? Bus? Walk?''","words":[{"character":"去","pinyin":"qù","english":"To go","context":"I go to the bazaar. 我去大巴扎。"},{"character":"出租车","pinyin":"chū zū chē","english":"Taxi","context":"Take a taxi. 坐出租车。"},{"character":"飞机","pinyin":"fēi jī","english":"Airplane","context":"I flew here. 我坐飞机来的。"},{"character":"在哪儿","pinyin":"zài nǎr","english":"Where is","context":"Where is the bazaar? 大巴扎在哪儿？"}]},{"type":"quiz","title":"Lost in Kashgar","narrative":"Lily gets lost in the maze-like old city. She needs help.","dialogue":"Lily: ''I don''t know where I am. I need to ask someone.''","question":"How does Lily ask for directions?","options":["请问，怎么走？","这个东西多少钱？","你叫什么名字？","现在几点？"],"answer":"请问，怎么走？","feedback":"An elderly Uyghur woman takes Lily''s hand and guides her through the alleys. She doesn''t speak Mandarin, but kindness needs no translation."},{"type":"learn","title":"Market Finds","narrative":"At the bazaar, Lily is overwhelmed by sights and smells: cumin, saffron, grilled lamb, fresh naan.","speaker":"lily","mood":"excited","dialogue":"Lily: ''I want to buy everything! But first — what is that amazing smell?''","words":[{"character":"买","pinyin":"mǎi","english":"To buy","context":"I want to buy this. 我想买这个。"},{"character":"东西","pinyin":"dōng xi","english":"Things/stuff","context":"So many things! 好多东西！"},{"character":"吃","pinyin":"chī","english":"To eat","context":"I want to eat lamb skewers!"}]},{"type":"quiz","title":"An Invitation","narrative":"The elderly woman who helped Lily invites her for tea. She gestures warmly.","dialogue":"Old woman: (gesturing) 来！喝茶！(Come! Drink tea!)","question":"What should Lily say?","options":["谢谢！(Thank you!)","多少钱？(How much?)","再见！(Goodbye!)","对不起！(Sorry!)"],"answer":"谢谢！(Thank you!)","feedback":"Lily sits with the woman, her daughter, her grandchildren. They share tea, naan, and smiles. Lily understands maybe 10% of the words — but 100% of the warmth."},{"type":"end","title":"Silk Road Lessons","narrative":"Lily writes on the rooftop of her hostel, watching the sunset over Kashgar.","speaker":"lily","mood":"reflective","dialogue":"Today I got lost and found a family. An Uyghur grandmother held my hand. We shared tea without sharing a language. Maybe that''s the real Silk Road — not silk or spices, but people meeting people. Grandma, did you feel this too?"}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "Province" ("id", "name", "capital", "culturalDescription", "landmark", "landmarkFact", "food", "foodDescription", "custom", "mapCoordinates", "unlockOrder", "color", "imageUrl", "storyContent", "courseId") VALUES ('017b48cf-11a0-45e2-ab3a-d5b61db0adb0', 'Hong Kong', '香港 (Xiānggǎng)', 'Your journey ends in Hong Kong — where East truly meets West. A former British colony returned to China in 1997, Hong Kong pulses with unique energy: gleaming skyscrapers, ancient temples, the world''s best dim sum, and a skyline that lights up every night in the Symphony of Lights.', 'Victoria Peak (太平山 Tàipíng Shān)', 'The Peak Tram has been climbing Victoria Peak since 1888. The view from the top — skyscrapers, harbor, and mountains all in one frame — is one of the most iconic cityscapes on Earth.', 'Egg Waffles (鸡蛋仔 jīdàn zǎi)', 'Crispy on the outside, soft and eggy inside — these bubble-shaped waffles are Hong Kong''s favorite street snack.', 'Hong Kong people walk fast — one of the fastest pedestrian speeds in the world! "Mm goi" (唔該) is the all-purpose Cantonese phrase for please, thank you, and excuse me.', '{"x":600,"y":560}', 9, '#e11d48', 'http://127.0.0.1:54321/storage/v1/object/public/lesson-images/hong-kong.jpg', '[{"type":"intro","title":"The Final Stop","narrative":"Lily''s last stop. Hong Kong''s skyline rises from Victoria Harbour like a crystal garden. She thinks about her first day in Beijing — couldn''t read a sign, couldn''t ask for help. Now look at her.","speaker":"narrator","mood":"reflective","dialogue":"Lily: ''I started this journey with 你好 and 谢谢. Let''s see how far I''ve come.''"},{"type":"learn","title":"Review: Everyday Life","narrative":"Lily navigates Hong Kong with confidence. She reviews essential words from her journey.","speaker":"lily","mood":"confident","dialogue":"Lily: ''I can order food, ask for directions, introduce myself. Let''s review!''","words":[{"character":"电话","pinyin":"diàn huà","english":"Telephone","context":"Lily needs to make a call."},{"character":"手机","pinyin":"shǒu jī","english":"Mobile phone","context":"Her phone has photos from the whole trip."},{"character":"书","pinyin":"shū","english":"Book","context":"She bought a book about Hong Kong history."},{"character":"牛奶","pinyin":"niú nǎi","english":"Milk","context":"Hong Kong milk tea is famous!"}]},{"type":"quiz","title":"The Peak","narrative":"Lily takes the Peak Tram to Victoria Peak. The view takes her breath away.","dialogue":"Lily: (to herself) ''I''ve come so far. From zero Chinese to... this.''","question":"How might Lily describe the view?","options":["很漂亮！(Beautiful!)","太辣了！(Too spicy!)","多少钱？(How much?)","现在几点？(What time?)"],"answer":"很漂亮！(Beautiful!)","feedback":"Hong Kong spreads out below her — mountains, harbor, skyscrapers, islands. ''很漂亮,'' she whispers. Her first Chinese word was 你好. Now she can describe beauty in another language."},{"type":"learn","title":"Final Review","narrative":"Lily writes postcards to everyone she met on her journey.","speaker":"lily","mood":"grateful","dialogue":"Lily: ''I want to write thank you notes. In Chinese.''","words":[{"character":"谢谢","pinyin":"xiè xie","english":"Thank you","context":"Thank you for everything. 谢谢你们。"},{"character":"再见","pinyin":"zài jiàn","english":"Goodbye","context":"Not goodbye — see you again. 再见。"},{"character":"爱","pinyin":"ài","english":"Love","context":"With love, Lily. 爱你的，小莉。"}]},{"type":"quiz","title":"The Journal","narrative":"Lily opens her grandma''s journal to the last page. There''s a message she somehow missed.","dialogue":"Grandma''s handwriting: ''小莉，去中国吧。那里有你的根。''(Xiao Li, go to China. Your roots are there.)","question":"Did Lily fulfill her grandma''s wish?","options":["Yes — she traveled across China and learned Chinese","No — she never left Beijing","She only visited one city","She gave up after day one"],"answer":"Yes — she traveled across China and learned Chinese","feedback":"Lily closes the journal. She DID learn Chinese. She DID find her roots. And somewhere along the way, she found herself too."},{"type":"end","title":"See You Again","narrative":"Lily writes the final entry in her own travel journal, at Victoria Peak, as the sun sets over Hong Kong.","speaker":"lily","mood":"reflective","dialogue":"Grandma, I did it. 9 cities. 150+ words. Countless bowls of noodles, wrong turns, new friends, and moments of pure joy. I came to China to learn a language. I learned that language is just the beginning — it''s the people, the food, the history, the kindness of strangers. 谢谢，奶奶。再见 — but not goodbye. I''ll be back."}]', '4a96dd0c-cc60-4238-b255-5f8015ffb149') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('05664b48-1889-4d79-9fac-0008a91e3766', '你好', 'nǐ hǎo', 'Hello', 'Greetings', '你好！欢迎来北京！(Hello! Welcome to Beijing!)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('f27766cf-8bb5-43b8-b82c-971931f42688', '我', 'wǒ', 'I, me', 'Pronouns', '我是游客，第一次来北京。(I am a tourist, visiting Beijing for the first time.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('a4d2ad66-2dec-4cce-94ca-5fe73fae154e', '你', 'nǐ', 'You', 'Pronouns', '你是北京人吗？(Are you from Beijing?)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('41ea2a3e-4e44-43ec-a142-5921d03dbd20', '他', 'tā', 'He', 'Pronouns', '他是我的导游。(He is my tour guide.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('59a61661-e0de-4bbb-93a9-6e57c312685e', '她', 'tā', 'She', 'Pronouns', '她很喜欢故宫。(She really likes the Forbidden City.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('dd545354-3a53-46cb-9420-f78535395579', '是', 'shì', 'To be', 'Verbs', '北京是中国的首都。(Beijing is the capital of China.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('e46cc171-505d-4af3-9855-5c37a6f977b9', '中国', 'Zhōngguó', 'China', 'Places', '中国很大，北京在北方。(China is big, Beijing is in the north.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('5610d044-f453-4f39-a3d1-c4a4232bdc24', '人', 'rén', 'Person', 'People', '北京有两千多万人。(Beijing has over 20 million people.)', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
