INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('fd97f23f-a985-4131-a3ea-aac4a392fb25', '牛奶', 'niúnǎi', 'Milk', 'Food', '香港的奶茶很好喝。(Hong Kong milk tea is delicious.)', '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
