INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('29e8795d-b9d9-47be-b1f6-42b4ec63dee2', '椅子', 'yǐzi', 'Chair', 'Objects', NULL, '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('1976fb5f-bf48-425d-a8ac-3b6442cb5f7f', '书', 'shū', 'Book', 'Objects', '我在书店买了一本关于香港历史的书。(I bought a book about Hong Kong history at the bookstore.)', '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('379de335-eb12-4f0f-b7b1-05d9d9d57e31', '日', 'rì', 'Day (formal)', 'Time', NULL, '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('7ebd2b61-4eee-4450-b72c-3508f1d4715b', '岁', 'suì', 'Years of age', 'Measure Words', '香港回归中国多少岁了？(How many years since Hong Kong returned to China?)', '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
INSERT INTO "VocabularyWord" ("id", "character", "pinyin", "english", "category", "travelSentence", "provinceId") VALUES ('a28ef87e-edfd-4870-a2c2-5bbb68d2efd0', '本', 'běn', 'Measure word (books)', 'Measure Words', '我买了三本书。(I bought three books.)', '017b48cf-11a0-45e2-ab3a-d5b61db0adb0') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('f36b2a24-58e1-4ee9-b212-61c938c9975f', 'Basic Sentence Structure (SVO)', 'Chinese follows Subject-Verb-Object order, just like English. Start here and you can already make thousands of sentences.', '[{"chinese":"我去故宫。","pinyin":"Wǒ qù Gùgōng.","english":"I go to the Forbidden City."},{"chinese":"她是北京人。","pinyin":"Tā shì Běijīng rén.","english":"She is from Beijing."}]', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('5f52dd7c-bb6d-46cd-8a9d-bbd62a9e213e', 'Questions with 吗 (ma)', 'Add 吗 at the end of any statement to turn it into a yes/no question. No word order change needed!', '[{"chinese":"你是北京人吗？","pinyin":"Nǐ shì Běijīng rén ma?","english":"Are you from Beijing?"},{"chinese":"长城远吗？","pinyin":"Chángchéng yuǎn ma?","english":"Is the Great Wall far?"}]', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('23f2c35f-de74-41e4-a5b0-bfcba1b1ef3e', 'Telling Time: Time + Verb', 'In Chinese, the time phrase goes BEFORE the verb, not at the end like English.', '[{"chinese":"我们九点去兵马俑。","pinyin":"Wǒmen jiǔ diǎn qù Bīngmǎyǒng.","english":"We go to the Terracotta Warriors at 9 o''clock."},{"chinese":"明天早上七点起床。","pinyin":"Míngtiān zǎoshang qī diǎn qǐchuáng.","english":"Tomorrow morning I get up at 7 o''clock."}]', '454e1d2c-349a-47e0-9569-f3ad7db48faf') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('47994fd8-6498-487b-acfe-e7aa2a0e32a3', 'The 了 (le) Particle - Completed Actions', '了 after a verb marks that an action is completed. Think of it as checking something off your travel list.', '[{"chinese":"我看了兵马俑。","pinyin":"Wǒ kàn le Bīngmǎyǒng.","english":"I saw the Terracotta Warriors (✓ done!)."},{"chinese":"我吃了biangbiang面。","pinyin":"Wǒ chī le biangbiang miàn.","english":"I ate biangbiang noodles (✓ done!)."}]', '454e1d2c-349a-47e0-9569-f3ad7db48faf') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('9e4d4000-87ff-4d57-af74-a9ac0eb16421', '太 + Adjective + 了 — "Too..."', 'Wrap太 (tài) and 了 (le) around an adjective to say something is "too X". Very useful at Sichuan restaurants!', '[{"chinese":"火锅太辣了！","pinyin":"Huǒguō tài là le!","english":"The hotpot is too spicy!"},{"chinese":"熊猫太可爱了！","pinyin":"Xióngmāo tài kě''ài le!","english":"Pandas are too cute!"}]', '6bef1815-3d73-4220-8a44-550ec954e10c') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('8ae8f2f9-4958-48ee-9708-793fbae14386', 'Adjectives as Predicates with 很 (hěn)', 'Chinese adjectives behave like verbs. Use 很 before the adjective (even when you don''t mean "very").', '[{"chinese":"四川菜很辣。","pinyin":"Sìchuān cài hěn là.","english":"Sichuan food is spicy."},{"chinese":"成都的茶馆很舒服。","pinyin":"Chéngdū de cháguǎn hěn shūfu.","english":"Chengdu''s teahouses are comfortable."}]', '6bef1815-3d73-4220-8a44-550ec954e10c') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('249faa4b-540c-451a-9626-af6982071c42', 'Negation with 没 (méi) — Past & Possession', '没 negates 有 (to not have) or past actions. Different from 不 which is for present/future.', '[{"chinese":"我没去过外滩。","pinyin":"Wǒ méi qù guo Wàitān.","english":"I haven''t been to the Bund."},{"chinese":"我没有时间逛街。","pinyin":"Wǒ méi yǒu shíjiān guàngjiē.","english":"I don''t have time to go shopping."}]', 'd7d98dea-244a-4065-9306-84e8eaa5398b') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('0051262c-8948-45a6-9761-ffb19f05afef', '吧 (ba) — Making Suggestions', 'Add 吧 at the end of a sentence to turn it into a friendly suggestion or soften a command.', '[{"chinese":"我们走吧！","pinyin":"Wǒmen zǒu ba!","english":"Let''s go!"},{"chinese":"去外滩拍照吧。","pinyin":"Qù Wàitān pāizhào ba.","english":"Let''s go take photos at the Bund."}]', 'd7d98dea-244a-4065-9306-84e8eaa5398b') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('15a80de4-b0c9-44e5-b655-25aadf2ea0e9', '在 (zài) — Location & Progressive Action', '在 means "at/in/on" for location. Placed before a verb, it marks ongoing action (like "-ing").', '[{"chinese":"我在大理。","pinyin":"Wǒ zài Dàlǐ.","english":"I am in Dali."},{"chinese":"我在喝普洱茶。","pinyin":"Wǒ zài hē Pǔ''ěr chá.","english":"I am drinking Pu''er tea."}]', '4177f051-f9b1-45c1-a8c3-4b7c031e658d') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('ff395e03-a624-42a7-b7d5-61dcce253b52', 'Location Words (上 下 里 前 后)', 'Direction words go AFTER the noun in Chinese — the opposite of English prepositions.', '[{"chinese":"山上","pinyin":"shān shàng","english":"on the mountain (literally: mountain-on)"},{"chinese":"石林里面","pinyin":"Shílín lǐmiàn","english":"inside the Stone Forest"}]', '4177f051-f9b1-45c1-a8c3-4b7c031e658d') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('638aaea5-8544-4911-8d58-8b20ee2c6b12', '会 (huì) — Learned Ability vs 能 (néng) — Possibility', '会 = learned skill (I can because I studied). 能 = possibility/permission (I can because the situation allows).', '[{"chinese":"我会用筷子。","pinyin":"Wǒ huì yòng kuàizi.","english":"I can use chopsticks (I learned how)."},{"chinese":"我不能吃花生。","pinyin":"Wǒ bù néng chī huāshēng.","english":"I cannot eat peanuts (allergy/restriction)."}]', '0dffd1de-a3fc-4a27-95fb-683abf3a3963') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('aec8fa63-f1b1-456e-826d-1c94c787b152', '呢 (ne) — Follow-up Questions & "What about...?"', 'Use 呢 to bounce a question back: "and you?" or "what about X?" You don''t need to repeat the full question.', '[{"chinese":"我会功夫，你呢？","pinyin":"Wǒ huì gōngfu, nǐ ne?","english":"I can do kung fu — and you?"},{"chinese":"我的书包呢？","pinyin":"Wǒ de shūbāo ne?","english":"What about my backpack? (Where is it?)"}]', '2c0319cd-8f99-4f52-8f4f-75699c40b0c6') ON CONFLICT DO NOTHING;
INSERT INTO "GrammarPoint" ("id", "title", "explanation", "examples", "provinceId") VALUES ('2d1ff406-9402-49e5-b7d5-2862fb3b79f9', 'Direction Complements — Where Are You Going?', 'Chinese uses direction words after verbs to show where the action is headed. 去 (go) + place is the simplest form.', '[{"chinese":"我去大巴扎。","pinyin":"Wǒ qù Dà Bāzhā.","english":"I''m going to the Grand Bazaar."},{"chinese":"飞机飞到乌鲁木齐。","pinyin":"Fēijī fēi dào Wūlǔmùqí.","english":"The plane flies to Urumqi."},{"chinese":"出租车开到天山脚下。","pinyin":"Chūzūchē kāi dào Tiānshān jiǎoxià.","english":"The taxi drives to the foot of the Tianshan Mountains."}]', 'daafe1b8-ccbb-4e89-abb1-a35a8daeeae3') ON CONFLICT DO NOTHING;
INSERT INTO "Exercise" ("id", "type", "question", "questionLabel", "options", "correctAnswer", "provinceId") VALUES ('c8440253-9d13-4543-9f2e-72d4ec037225', 'CULTURAL', 'What does "你好" (nǐ hǎo) mean?', 'Greetings', '["Hello","Goodbye","Thank you","Sorry"]', 'Hello', 'deaf9549-9a72-4827-880f-004120365c2c') ON CONFLICT DO NOTHING;
